qry:select.qry:xquery:
					for $r in SQL('
{%? (#SOURCE:@START='') {% %} {% fromrow {%=#SOURCE:@START %} %} %} 
 {%? (#SOURCE:@LEN='') {% %} {% maxsize {%=#SOURCE:@LEN %} %} %} 
select
  TTA09_LIQUIDACION.oi_liquidacion as ID,
  TTA09_LIQUIDACION.c_liquidacion as COD,
  TTA09_LIQUIDACION.d_liquidacion as DES
from
  TTA09_LIQUIDACION
Where
  1=1 
{%? (#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %} 
{%? (#SOURCE:@TXT_FIND='') {% %} {% and (contain(DES,{#SOURCE:@TXT_FIND}) or contain(COD,{#SOURCE:@TXT_FIND})) %} %} 
{%? (#SOURCE:@OI_PARENT='') {% %} {% and PARENT={#SOURCE:@OI_PARENT} %} %} 

{%? (#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE %} %} %}
{%? (#SOURCE:@ORDERBY='') {% order by DES asc %} {%  order by {%=#SOURCE:@ORDERBY %} asc %} %}')/ROWS/ROW

			for $r in sql(' 
		SELECT TTA02_HORARIOS.e_iniciodia
		FROM TTA04_HORARIOSPERS, TTA02_HORARIOS
		JOIN TTA04_HORARIOSPERS.oi_horario INNER TTA02_HORARIOS.oi_horario
		WHERE TTA04_HORARIOSPERS.f_fechainicio <= {Datetime(#SOURCE:@f_des)}
		AND (TTA04_HORARIOSPERS.f_fechafin >= {Datetime(#SOURCE:@f_des)}
					OR ISNULL(TTA04_HORARIOSPERS.f_fechafin))
		AND TTA04_HORARIOSPERS.oi_personal_emp = {#SOURCE:@oi_personal_emp} 
 	')/ROWS/ROW

		for $r in sql(' 
	SELECT TTA02_HORARIOS.e_iniciodia
	FROM TTA04_HORARIOSPERS, TTA02_HORARIOS
	JOIN TTA04_HORARIOSPERS.oi_horario INNER TTA02_HORARIOS.oi_horario
	WHERE TTA04_HORARIOSPERS.f_fechainicio <= {Datetime(#SOURCE:@f_has)}
	AND (TTA04_HORARIOSPERS.f_fechafin >= {Datetime(#SOURCE:@f_has)}
				OR ISNULL(TTA04_HORARIOSPERS.f_fechafin))
	AND TTA04_HORARIOSPERS.oi_personal_emp = {#SOURCE:@oi_personal_emp} 
')/ROWS/ROW

		for $r in sql('			
	SELECT  COUNT(TTA07_FICHADASING.oi_fichadasing) AS f_ing_cont
	FROM TTA07_FICHADASING
	WHERE TTA07_FICHADASING.oi_personal_emp = {#FILTRO:@oi_personal_emp}
	AND TTA07_FICHADASING.f_fechahora >= {DateTime(#FILTRO:@liq_des)}
	AND TTA07_FICHADASING.f_fechahora < {DateTime(#FILTRO:@liq_has)}
  AND TTA07_FICHADASING.c_estado != \'A\'
')/ROWS/ROW

		for $r in sql('							
	SELECT {%=#PARAM:@f_ing_cont%} AS f_ing_cont, 
	COUNT(TTA08_FICHADAS.oi_fichada) AS f_fic_cont
	FROM TTA08_FICHADAS
	WHERE TTA08_FICHADAS.oi_personal_emp =  {#FILTRO:@oi_personal_emp}
	AND TTA08_FICHADAS.f_fechahora >= {DateTime(#FILTRO:@liq_des)}
	AND TTA08_FICHADAS.f_fechahora < {DateTime(#FILTRO:@liq_has)}
	AND TTA08_FICHADAS.oi_liquidacion = {#FILTRO:@oi_liquidacion}
')/ROWS/ROW

class.resource:
			using System;
using System.Xml;
using System.Collections;
using System.Text;
using System.Reflection;

using Nomad.NSystem.Functions;
using Nomad.NSystem.Document;
using Nomad.NSystem.Proxy;
using Nomad.NSystem.Base;
using NucleusRH.Base.Tiempos_Trabajados;

namespace NucleusRH.Base.Tiempos_Trabajados.RHLiq
{
	public class LiqConceptos : LiqConceptosBase
	{
{conCONCEPTO}

		override public void ApplyConceptos(Liquidacion.LIQUIDACION myliq, Personal.PERSONAL_EMP myper, Liquidacion_Personas.LIQUIDACIONPERS myperliq, ArrayList arrayHope)
		{                                                          
			SetLegajo(myper.descr);
			InitializeLiquidacion(myliq);                             
			InitializePersona(myper, myperliq);

			Hashtable dias = new Hashtable();
			foreach(Esperanzaper.DIA myDIA in arrayHope)
			{
				dias[myDIA.f_dia] = myDIA;
			}            

			foreach (Liquidacion_Personas.LIQUIDACJOR jor in myperliq.LIQUIDACJOR)
			{                                           
				jor.myliq = myliq;
				foreach (Liquidacion_Personas.LIQUIDACIONPROC proc in jor.LIQUIDACPROC)
					proc.Day = jor.f_fecjornada;

				IniciarVariableHoras(jor);
				SetFecha(jor.f_fecjornada.ToString("dd/MM/yyyy"));
				this.FechaActual = jor.f_fecjornada;
{conCALLDIA}
			}	
			IniciarVariableHoras(null);
			SetFecha("");
{conCALLMES}

      //Elimino los Conceptos no Liquidados
      ArrayList MyDeleteConc=new ArrayList();
			foreach (Liquidacion_Personas.CONC_VAL conc in myperliq.CONC_PER)
			{                                          
				if (!conc.IsForUpdate && !conc.IsForInsert)  
					MyDeleteConc.Add(conc);
			}
			foreach (Liquidacion_Personas.CONC_VAL conc in MyDeleteConc)
				myperliq.CONC_PER.Remove(conc);


			ActualizarAcumuladores();                                     
		}

	}
}

			static double CONC_{code}(Liquidacion_Personas.LIQUIDACIONPERS PER, Liquidacion_Personas.LIQUIDACJOR JOR, Esperanzaper.DIA HDIA {VAR_DECLARE})
{      
//BEGCONC: {code}
	{formula}
//ENDCONC:
}

void CALL_CONC_{code}(Liquidacion_Personas.LIQUIDACIONPERS PER, Liquidacion_Personas.LIQUIDACJOR JOR, Esperanzaper.DIA HDIA)
{
	SetConcepto("{code}");
	double retval;    
	int clave=(JOR!=null?int.Parse(JOR.f_fecjornada.ToString("yyyyMMdd")):0);

	{VAR_READ}
	retval=CONC_{code}(PER, JOR, HDIA {VAR_CALL});
	{VAR_SET}

	//Valor Distinto de CERO GUARDAR
	Liquidacion_Personas.CONC_VAL myCONC=Find_CONC_PER(PER, "{id}", clave); 
	if (retval!=0)
	{
		if (myCONC==null)
		{
			myCONC=new Liquidacion_Personas.CONC_VAL();
			myCONC.oi_concepto="{id}";
			if (JOR!=null) myCONC.e_clave=clave;
			myCONC.n_valor=retval;
			PER.CONC_PER.Add(myCONC);
		} else
			myCONC.n_valor=retval;
	} else               
	if (myCONC!=null)  
		PER.CONC_PER.Remove(myCONC);
}
